/// Wrapper for versioned API responses
#[derive(Debug, Clone, Serialize, Deserialize)]
#[serde(rename_all = "camelCase")]
pub struct VersionedResponse<T> {
    /// The API version used for this response
    pub api_version: String,
    /// The actual response data
    pub data: T,
    /// Deprecation warning if applicable
    #[serde(skip_serializing_if = "Option::is_none")]
    pub deprecation_warning: Option<String>,
}

impl<T> VersionedResponse<T> {
    /// Create a new versioned response
    pub fn new(version: ApiVersion, data: T) -> Self {
        let deprecation_warning = if version.is_deprecated() {
            version.deprecation_message().map(|s| s.to_string())
        } else {
            None
        };
        
        Self {
            api_version: version.as_str().to_string(),
            data,
            deprecation_warning,
        }
    }
}

